1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("Quote - base premiums", () => {
6	    it("returns 5 G processing fee for an empty item list", () => {
7	      const scenario = {
8	        customer: { yearsWithMHPCO: 0 },
9	        steps: [{ op: "quote" as const, items: [] }],
10	      };
11	      const result = processScenario(scenario);
12	      expect(result.results[0].premium).toBe(5);
13	    });
14	    it.todo("returns base premium plus fee for a single sword");
15	    it.todo("returns base premium plus fee for each main item type (amulet, staff, potion)");
16	    it.todo("returns 25 G base premium per component (rune)");
17	    it.todo("applies building block discount for exactly 3 alike components");
18	    it.todo("does not apply block discount for 4 alike components");
19	    it.todo("treats different component types separately for block eligibility");
20	    it.todo("sums base premiums for multiple items in a policy");
21	  });
22	
23	  describe("Quote - item-specific modifiers", () => {
24	    it.todo("adds 50% cursed surcharge to the cursed item base premium");
25	    it.todo("adds 30% high-enchantment surcharge for enchantment level >= 5");
26	    it.todo("applies both cursed and high-enchantment surcharges to the same item");
27	    it.todo("applies item modifiers only to the affected item in a multi-item policy");
28	  });
29	
30	  describe("Quote - policy-wide modifiers", () => {
31	    it.todo("applies 10% first-insurance surcharge on policy base premium");
32	    it.todo("applies 20% loyalty discount for customer with >= 2 years");
33	    it.todo("applies 15% follow-up discount on second and subsequent quotes");
34	    it.todo("stacks policy-wide modifiers (loyalty, first insurance, follow-up)");
35	  });
36	
37	  describe("Quote - rounding", () => {
38	    it.todo("rounds premium up (in MHPCO's favor)");
39	  });
40	
41	  describe("Quote - integration", () => {
42	    it.todo("newcomer with cursed sword computes to 165 G");
43	    it.todo("long-standing customer second contract with cursed high-enchantment sword computes to 160 G");
44	  });
45	
46	  describe("Claim - standard reimbursement", () => {
47	    it.todo("reimburses damage minus 100 G deductible for a regular item");
48	    it.todo("reimburses component damage minus deductible");
49	    it.todo("applies deductible per damaged item in a single event");
50	  });
51	
52	  describe("Claim - special clauses", () => {
53	    it.todo("reimburses at 50% for items with enchantment >= 8, then deductible");
54	    it.todo("fully reimburses dragon-material items minus deductible");
55	    it.todo("applies 50% rule when both dragon material and enchantment >= 8");
56	    it.todo("applies only dragon-material clause when enchantment < 8");
57	  });
58	
59	  describe("Claim - cap", () => {
60	    it.todo("caps total payout at twice the insurance sum");
61	    it.todo("tracks remaining cap across successive claims");
62	    it.todo("bases cap on unmodified insurance values");
63	  });
64	
65	  describe("Claim - rounds payout down (in MHPCO's favor)", () => {
66	    it.todo("rounds payout down");
67	  });
68	
69	  describe("Validation", () => {
70	    it.todo("rejects unknown item type in a quote");
71	    it.todo("rejects claim for item not in policy");
72	    it.todo("rejects claim with more damage entries than insured items of that type");
73	    it.todo("rejects negative damage amount");
74	  });
75	});
76

